const articles = {
    "massage-relaxation": {
        "title": "Manfaat Pijat Relaksasi untuk Kesehatan",
        "content": "Pijat telah digunakan selama berabad-abad untuk membantu mengurangi ketegangan otot...",
        "description": "Pelajari manfaat pijat relaksasi untuk kesehatan tubuh dan pikiran Anda."
    },
    "aromatherapy": {
        "title": "Aromaterapi: Cara Alami Mengatasi Stres",
        "content": "Aromaterapi dapat membantu menenangkan pikiran dan meningkatkan kualitas tidur Anda...",
        "description": "Manfaat aromaterapi dalam meredakan stres dan meningkatkan kualitas hidup."
    }
};

function loadArticle() {
    let urlParams = new URLSearchParams(window.location.search);
    let articleKey = urlParams.get("article");
    let contentSection = document.querySelector(".blog-post-content");

    if (articles[articleKey]) {
        document.title = articles[articleKey].title + " | Salsabila Spa";
        document.querySelector('meta[name="description"]').setAttribute("content", articles[articleKey].description);
        
        contentSection.innerHTML = `<h1>${articles[articleKey].title}</h1><p>${articles[articleKey].content}</p>`;
    } else {
        contentSection.innerHTML = "<h1>Artikel Tidak Ditemukan</h1><p>Maaf, artikel yang Anda cari tidak tersedia.</p>";
    }
}

window.onload = loadArticle;
